refsection.programlisting:
      
rng = lowdisc_new("sobol");
rng = lowdisc_configure(rng,"-dimension",4);
rng = lowdisc_startup (rng);
// Get first point
[rng,computed]=lowdisc_next(rng);
// Get second point
[rng,computed]=lowdisc_next(rng);
// Get 1000 points
[rng,computed]=lowdisc_next(rng,1000);
rng = lowdisc_destroy(rng);

      
// Get all the available sequences.
seqmat = lowdisc_methods ();
// Get the speed, maximum dimension and
// maximum number of calls for all sequences
seqmat = lowdisc_methods ();
mprintf("%-20s %-10s %-10s\n", "Name" , ..
"Max Dim" , "Max Call" );
for seqname = seqmat'
    lds = lowdisc_new(seqname);
    dimmax = lowdisc_get(lds,"-dimmax");
    nbsimmax = lowdisc_get(lds,"-nbsimmax");
    mprintf("%-20s %-10d %-10d\n", seqname , ..
    dimmax , nbsimmax );
    lds = lowdisc_destroy(lds);
end
